//! Milestone 4a commit 3 — byte-for-byte parity tests for the single-party
//! Aptos CA `TransferV1` sigma proof reference port.
//!
//! These tests load the committed fixture from
//! `operator-services/deop-protocol/tests/fixtures/aptos_ca_transfer_v1_fixture.json`
//! (generated by the TS fixture script with a deterministic SHA-256 PRNG keyed
//! by `EUNOMA_APTOS_CA_TRANSFER_V1_FIXTURE_PRNG_SEED`) and assert that the
//! Rust prover output is byte-identical to the Aptos SDK output.

use std::{fs, path::PathBuf};

use curve25519_dalek::scalar::Scalar;
use curve25519_dalek::{
    constants::RISTRETTO_BASEPOINT_POINT, ristretto::RistrettoPoint, traits::Identity,
};
use eunoma_crypto_worker::transfer_sigma_reference::{
    bcs_fiat_shamir_inputs, bcs_serialize_transfer_session, build_statement, prng_next_scalar_list,
    prove_transfer_single_party, sigma_fiat_shamir_seed,
    threshold::{
        aggregate_threshold_sigma_commitments, aggregate_threshold_sigma_responses,
        compute_threshold_sigma_partial_commitment, compute_threshold_sigma_response_share,
        derive_dk_base_points, COMMITMENT_LEN, WITNESS_LEN,
    },
    verify_transfer_single_party, CounterPrng, DomainSeparator, SigmaProtocolProof,
    TransferStatementInputs, APTOS_FRAMEWORK_ADDRESS, PROTOCOL_ID, TYPE_NAME,
};
use serde::Deserialize;

const FIXTURE_REL_PATH: &str = "../deop-protocol/tests/fixtures/aptos_ca_transfer_v1_fixture.json";

const SDK_FILE_REF: &str = "@aptos-labs/confidential-asset/src/crypto/sigmaProtocolTransfer.ts";

